(window.webpackJsonp=window.webpackJsonp||[]).push([[129],{756:function(n,t){n.exports="\x3c!-- \ntitle: 01-Python基础\nsort: \n--\x3e \n## python学习阶段常用命令\n\n- `dir()`\n\n  > 返回属性列表\n  >\n  > 可用于查看一个对象的所有方法\n\n- `type()`\n\n  > 返回对象类型\n  \n- `help()`\n\n  > 返回对象帮助\n\n- `id()`\n\n  > 返回对象内存地址\n\n## 数据类型\n\n### `list`\t列表\n\n> list.append()\t\t追加元素\n>\n> list.insert()\t\t\t插入元素至指定位置\n>\n> list.pop\t\t\t\t\t删除末尾元素\n\n### `tuple`\t元组\n\n> tuple = ( )\t\t\t\t使用（）\t\n>\n> tuple = ( 1 , )\t\t\t定义一个数据必须加括号\n>\n> t = ('a', 'b', [\"a\"])\t\t定义一个”可变“tuple\n\n### `dict`\t字典\n\n> d = {'a': 5, 'b': 6}\t\t定义一个字典\n>\n> d = dict([('a', 1), ('b', 2)])\t\n>\n> d.get('x', val)\t\t\tx不存在的返回值\t\n>\n> 不准许放入列表\t\n\n\n\n## 函数\n\n### 传参\n\n> `function(a, b, *change )`\t\n>\n> 传入可变参数（即不需要名称的参数），所有参数放入一个名叫change的tuple。\n>\n> `function(a, b, **change )`\t\n>\n> 传入关键字参数（即带名称的参数），所有参数放入一个名为change的dict中。\n>\n> `function(a, *, bit)`\t\t\t\t\t\n>\n> 传入命名关键字参数，必须传入，参数名必须为bit\t例：「bit = \"233\"」\n>\n> `function(a, b, *args, bit, cat)`\t\n>\n> 假如有可变参数，就不用加\\*了\n>\n> `funcation(12, 34, bit, cat=2`)\t可以有缺省值，有默认值也可不传入\t\n\n### 参数组合\n\n- ```python\n  def f1(a, b, c = 1, *args, **kw):\n  ```\n\n  > ```python\n  > f1(1,2,5,'ai','py',dict = hh)\n  > >>> a = 1, b = 2, c = 5, args = ('ai','py'), kw = {dict:'hh'}\n  > \n  > args = (1, 2, 3, 4)\n  > kw = {'d': 99, 'x': '#'}\n  > f1(*args, **kw)\n  > >>> a = 1, b = 2, c = 3, args = (4,) kw = {'d': 99, 'x': '#'} \n  > ```\n\n  \n  "}}]);